mapper.select:

SELECT *
FROM 
	SYS_USER
WHERE
	ENABLED_FLAG=1


AND ID=#{id}


AND ACCT=#{acct}


AND upper(PWD) like upper('%${pwd}%')


AND upper(REAL_NAME) like upper('%${realName}%')


AND upper(MEMO) like upper('%${memo}%')


AND upper(EMAIL) like upper('%${email}%')


AND upper(EMAIL_ACTIVE) like upper('%${emailActive}%')


AND upper(STATUS) like upper('%${status}%')


AND LAST_UPDATE_DATE=#{lastUpdateDate}


AND LAST_UPDATED_BY=#{lastUpdatedBy}


AND CREATION_DATE=#{creationDate}


AND CREATED_BY=#{createdBy}


AND ENABLED_FLAG=#{enabledFlag}


AND LOGINS=#{logins}


AND LAST_LOGIN_TIME=#{lastLoginTime}


AND upper(NICKNAME) like upper('%${nickname}%')


AND ERRORTIMES=#{errortimes}


AND LOGINTIME=#{logintime}

ORDER BY ID


SELECT 
	*
FROM 
	SYS_USER
WHERE
	ENABLED_FLAG=1


AND ID=#{bo.id}


AND upper(ACCT) like upper('%${bo.acct}%')


AND upper(PWD) like upper('%${bo.pwd}%')


AND upper(REAL_NAME) like upper('%${bo.realName}%')


AND upper(MEMO) like upper('%${bo.memo}%')


AND upper(EMAIL) like upper('%${bo.email}%')


AND upper(EMAIL_ACTIVE) like upper('%${bo.emailActive}%')


AND upper(STATUS) like upper('%${bo.status}%')


AND LAST_UPDATE_DATE=#{bo.lastUpdateDate}


AND LAST_UPDATED_BY=#{bo.lastUpdatedBy}


AND CREATION_DATE=#{bo.creationDate}


AND CREATED_BY=#{bo.createdBy}


AND ENABLED_FLAG=#{bo.enabledFlag}


AND LOGINS=#{bo.logins}


AND LAST_LOGIN_TIME=#{bo.lastLoginTime}


AND upper(NICKNAME) like upper('%${bo.nickname}%')


AND ERRORTIMES=#{bo.errortimes}


AND LOGINTIME=#{bo.logintime}

ORDER BY ${page.sortFieldName} DESC
